#include <stdio.h>
#include <string.h>

/* == EXEMPLE ================================================
 * Ecrire du TSV (tab-separated) dans un buffer avec fprintf
 * fmemopen cree un FILE* depuis un tableau en RAM
 * =========================================================== */
void example_tsv(void) {
    char tbuf[256];
    memset(tbuf, 0, sizeof(tbuf));
    FILE *tf = fmemopen(tbuf, sizeof(tbuf), "w");
    if (!tf) return;
    fprintf(tf, "fruit\tprix\tstock\n");
    fprintf(tf, "pomme\t1.20\t50\n");
    fprintf(tf, "banane\t0.80\t120\n");
    fclose(tf);  /* flush obligatoire avant de lire tbuf */
    printf("%s", tbuf);
}
/* Resultat: tableau TSV fruit/prix/stock */

